    private void appendData(HSSFSheet sheet, int columnIndex, APIEntry e, String projectName, int db_year,
                            double totalCaseAmount, HashMap<Integer, Double> overallIncome, HashMap<Integer, Double> overallPayment, RagicBundle bundle) throws Exception {
        HSSFRow row = null;
        HSSFCell cell = null;

        row = sheet.getRow(2);
        cell = row.getCell(columnIndex);
        cell.setCellValue(projectName);


        String _holdDate = e.getFieldValue(HOLD_DATE); //執案日期
        String _endDate = e.getFieldValue(END_DATE);   //結案日期

        int dayCompare = Calendar.getInstance().getTime().compareTo(Encoder.parseDate(_endDate));

        // 執行進度
        row = sheet.getRow(3);
        cell = row.getCell(columnIndex);
        if (dayCompare > 0) {
            cell.setCellValue("已結案");
        } else {
            cell.setCellValue("進行中");
        }

        // 得標日期
        row = sheet.getRow(4);
        cell = row.getCell(columnIndex);
        cell.setCellValue(e.getFieldValue(ACCQUIRE_DATE));

        // 活動日
        row = sheet.getRow(5);
        cell = row.getCell(columnIndex);
        cell.setCellValue(_holdDate + "-" + _endDate);

        // 付款期數
        row = sheet.getRow(6);
        cell = row.getCell(columnIndex);
        cell.setCellValue(e.getFieldValue(PAYMENT_PERIODS));

        // 價金, 全案金額欄位 * 1.05
        Double projectFullAmount = Encoder.parseDouble(e.getFieldValue(PROJECT_FULL_AMOUNT));
        totalCaseAmount += projectFullAmount;
        row = sheet.getRow(7);
        cell = row.getCell(columnIndex);
        cell.setCellValue(projectFullAmount * 1.05);

        // 稅後價金, 全案金額欄位
        row = sheet.getRow(8);
        cell = row.getCell(columnIndex);
        cell.setCellValue(projectFullAmount);

        // 預估支出, 預估成本欄位
        row = sheet.getRow(9);
        cell = row.getCell(columnIndex);
        cell.setCellValue(e.getFieldValue(FORECASTED_COST));

        // 預稅後收, 預稅後收欄位
        row = sheet.getRow(10);
        cell = row.getCell(columnIndex);
        cell.setCellValue(e.getFieldValue(PRE_TAX_INCOME));

        // 預稅後比, 預估利潤欄位
        row = sheet.getRow(11);
        cell = row.getCell(columnIndex);
        cell.setCellValue(e.getFieldValue(FORECASTED_PROFIT));
    
    
        /*
        ** 收入、支出
        */
        // 收入
        int incomeSubEntryNum = e.getSubtableSize(PROJECT_SUBTABLE_INCONE_KEY);
        if (incomeSubEntryNum > 0) {
            HashMap<String, LinkedList<Object>> monthlyIncom = new HashMap<String, LinkedList<Object>>();

            for (int i = 0; i < incomeSubEntryNum; i++) {
                String _incomeDate = e.getSubtableFieldValue(PROJECT_SUBTABLE_INCONE_KEY, i, String.valueOf(INCOME_DATE));
                String _income = e.getSubtableFieldValue(PROJECT_SUBTABLE_INCONE_KEY, i, String.valueOf(INCOME_AMOUNT_PAID));
                if (_incomeDate.length() > 0 && _income.length() > 0) {
                    Calendar cal = Calendar.getInstance();
                    cal.setTime(Encoder.parseDate(_incomeDate));
                    int year = cal.get(Calendar.YEAR);
                    if (year != db_year) continue;
                    int month = cal.get(Calendar.MONTH);
                    int day = cal.get(Calendar.DAY_OF_MONTH);

                    double income = Encoder.parseDouble(_income);
                    String detail = e.getSubtableFieldValue(PROJECT_SUBTABLE_INCONE_KEY, i, String.valueOf(INCOME_ITEMS)) + "/" +
                            e.getSubtableFieldValue(PROJECT_SUBTABLE_INCONE_KEY, i, String.valueOf(INCOME_SUMMARY));

                    String storekey;
                    if (day > 15) {
                        storekey = month + "d";
                    } else {
                        storekey = month + "u";
                    }
                    if (monthlyIncom.containsKey(storekey)) {
                        LinkedList<Object> data = monthlyIncom.get(storekey);
                        data.set(0, (Double) data.get(0) + income);
                        data.set(1, data.get(1) + "、" + detail);
                    } else {
                        LinkedList<Object> data = new LinkedList<Object>();
                        data.add(income);
                        data.add(detail);
                        monthlyIncom.put(storekey, data);
                    }
                }
            }

            for (Map.Entry<String, LinkedList<Object>> entry : monthlyIncom.entrySet()) {
                String monthkey = entry.getKey();
                LinkedList<Object> data = entry.getValue();

                int month = Integer.parseInt(monthkey.substring(0, monthkey.length() - 1));
                boolean upperMonth = "u".equals(monthkey.substring(monthkey.length() - 1, monthkey.length()));
                int monthRow = 12 + month * 4 + (upperMonth ? 1 : 3);
                //write income
                row = sheet.getRow(monthRow);
                cell = row.getCell(columnIndex);
                cell.setCellValue((Double) data.get(0));
                //write remark
                row = sheet.getRow(monthRow + 1);
                cell = row.getCell(columnIndex);
                cell.setCellValue(data.get(1).toString());

                if (overallIncome.containsKey(monthRow)) {
                    overallIncome.put(monthRow, overallIncome.get(monthRow) + (Double) data.get(0));
                } else {
                    overallIncome.put(monthRow, (Double) data.get(0));
                }
            }
        }


        // 支出
        APIQuery payq = new APIQuery(apname, PATH, PAYMENT_SHEET_INDEX); // query form sheet "請款單"
        LinkedList<String> paymentFilters = new LinkedList<String>();
        paymentFilters.add(PAYMENT_PROJECT_NAME + "|" + NUIFilter.OPERAND_EQ + "|" + projectName);
        String firstDayString = db_year + "/01/01";
        String lastDayString = db_year + "/12/31";
        paymentFilters.add(PAYMENT_DEBIT_DAY + "|" + NUIFilter.OPERAND_GTE + "|" + firstDayString);
        paymentFilters.add(PAYMENT_DEBIT_DAY + "|" + NUIFilter.OPERAND_LTE + "|" + lastDayString);

        payq.setFiltersStringV2(paymentFilters.toArray(new String[paymentFilters.size()]));
        payq.setIfEidNaming(true);
        payq.setBundle(bundle);

        HashMap<String, Double> monthlyPayment = new HashMap<String, Double>();
        APIResults qdata = payq.getAPIResults();
        Iterator<APIEntry> iterator = qdata.iterator(payq.getForm());
        while (iterator.hasNext()) {
            APIEntry paye = iterator.next();
            String paidDate = paye.getFieldValue(PAYMENT_DEBIT_DAY);
            String payment = paye.getFieldValue(PAYMENT_AMOUNT_TAXIN);
            if (paidDate.length() > 0 && payment.length() > 0) {
                Calendar cal = Calendar.getInstance();
                cal.setTime(Encoder.parseDate(paidDate));
                int month = cal.get(Calendar.MONTH);
                int day = cal.get(Calendar.DAY_OF_MONTH);

                double _payment = Encoder.parseDouble(payment) * -1;
                String storekey;
                if (day > 15) {
                    storekey = month + "d";
                } else {
                    storekey = month + "u";
                }
                if (monthlyPayment.containsKey(storekey)) {
                    monthlyPayment.put(storekey, monthlyPayment.get(storekey) + _payment);
                } else {
                    monthlyPayment.put(storekey, _payment);
                }
            }
        }
        for (Map.Entry<String, Double> entry : monthlyPayment.entrySet()) {
            String monthkey = entry.getKey();
            Double payment = entry.getValue();

            int month = Integer.parseInt(monthkey.substring(0, monthkey.length() - 1));
            boolean upperMonth = "u".equals(monthkey.substring(monthkey.length() - 1, monthkey.length()));
            int monthRow = 12 + month * 4 + (upperMonth ? 1 : 3);
            //write payment
            row = sheet.getRow(monthRow);
            cell = row.getCell(columnIndex + 1);
            cell.setCellValue(payment);

            cell.getCellStyle().getFont(sheet.getWorkbook()).setColor(HSSFColor.HSSFColorPredefined.BLACK.getIndex());

            if (overallPayment.containsKey(monthRow)) {
                overallPayment.put(monthRow, overallPayment.get(monthRow) + payment);
            } else {
                overallPayment.put(monthRow, payment);
            }
        }

        // 屢保金，根據屢保金欄位 顯示在在支出
        row = sheet.getRow(61);
        cell = row.getCell(columnIndex + 1);
        String reserved_pay = e.getFieldValue(RESERVED_PAY);
        cell.setCellValue(Encoder.parseDouble(reserved_pay));
    }

    private void copyProjectCells(HSSFRow row, int sourceProjectCellIndex, int targetProjectCellIndex) {
        for (int i = 0; i < 2; i++) {  // run twice, Income and payment.
            HSSFCell oldCell = row.getCell(sourceProjectCellIndex + i);
            HSSFCell newCell = row.getCell(targetProjectCellIndex + i);
            if (newCell == null) {
                newCell = row.createCell(targetProjectCellIndex + i);
            }

            copyCell(oldCell, newCell);
        }
    }

    private void copyCell(HSSFCell oldCell, HSSFCell newCell) {
        // Use old cell style
        newCell.setCellStyle(oldCell.getCellStyle());

        // If there is a cell comment, copy
        if (newCell.getCellComment() != null) {
            newCell.setCellComment(oldCell.getCellComment());
        }

        // If there is a cell hyperlink, copy
        if (oldCell.getHyperlink() != null) {
            newCell.setHyperlink(oldCell.getHyperlink());
        }

        // Set the cell data type
        newCell.setCellType(oldCell.getCellType());

        // Set the cell data value
        switch (oldCell.getCellType()) {
            case BLANK:
                newCell.setCellValue(oldCell.getStringCellValue());
                break;
            case BOOLEAN:
                newCell.setCellValue(oldCell.getBooleanCellValue());
                break;
            case ERROR:
                newCell.setCellErrorValue(oldCell.getErrorCellValue());
                break;
            case FORMULA:
                String formula = oldCell.getCellFormula();
                String oldColumnRef = CellReference.convertNumToColString(oldCell.getColumnIndex()),
                        oldColumnRefNext = CellReference.convertNumToColString(oldCell.getColumnIndex() + 1),
                        newColumnRef = CellReference.convertNumToColString(newCell.getColumnIndex()),
                        newColumnRefNext = CellReference.convertNumToColString(newCell.getColumnIndex() + 1);

                String formulaRegex = oldColumnRef + "\\d|" + oldColumnRefNext + "\\d";
                Pattern pattern = Pattern.compile(formulaRegex);
                Matcher matcher = pattern.matcher(formula);
                while (matcher.find()) {
                    String _pattern = matcher.group(),
                            _newpattern = _pattern.replaceAll(oldColumnRef, newColumnRef)
                                    .replaceAll(oldColumnRefNext, newColumnRefNext);
                    formula = formula.replaceAll(_pattern, _newpattern);
                }

                newCell.setCellFormula(formula);
                break;
            case NUMERIC:
                newCell.setCellValue(oldCell.getNumericCellValue());
                break;
            case STRING:
                newCell.setCellValue(oldCell.getRichStringCellValue());
                break;
        }
    }

